        opt_code = '''
  // Special case: when ANDing with a constant mask, if the range has a minimum
  // value A > 0, and the mask preserves all high bits (bits >= highest bit of A),
  // then the result must also be >= A.
  if (const APInt *C = Other.getSingleElement()) {
    APInt A = getUnsignedMin();
    if (!A.isZero()) {
      // Check if C has all bits from the highest bit of A onwards set.
      // This is equivalent to checking if (C | (A - 1)) is all ones.
      APInt AllOnes = APInt::getAllOnes(getBitWidth());
      if ((C->Or(A - 1)) == AllOnes) {
        // The result must be >= A & C, and since C preserves high bits,
        // we know result >= A. But more precisely, result >= A & C.
        APInt MinResult = A & *C;
        if (!MinResult.isZero()) {
